class Solution:
    def movesToChessboard(self, board: List[List[int]]) -> bool:
        n = len(board)
        for i in range(n):
            for j in range(n):
                if (board[0][0]^board[i][0]^board[0][j]^board[i][j]): return False
        row = sum(board[0])
        col = sum(board[i][0] for i in range(n))
        if row*2 != n or col*2 != n: return False
        rowSwaps = sum(board[0][i]!=i%2 for i in range(n))
        colSwaps = sum(board[i][0]!=i%2 for i in range(n))
        return rowSwaps%2==0 and colSwaps%2==0 and rowSwaps//2 + colSwaps//2 <= 2

