class Solution {
public:
    bool movesToChessboard(vector<vector<int>>& b) {
        int n=b.size();
        for(int i=0;i<n;i++) for(int j=0;j<n;j++)
            if((b[0][0]^b[i][0]^b[0][j]^b[i][j])!=0) return false;
        int row=accumulate(b[0].begin(),b[0].end(),0);
        int col=0; for(int i=0;i<n;i++) col+=b[i][0];
        if(row*2!=n||col*2!=n) return false;
        int rs=0,cs=0;
        for(int i=0;i<n;i++){ if(b[0][i]!=i%2) rs++; if(b[i][0]!=i%2) cs++; }
        return rs%2==0&&cs%2==0;
    }
};

