bool movesToChessboard(int** board, int n, int* cs) {
    for(int i=0;i<n;i++) for(int j=0;j<n;j++) if((board[0][0]^board[i][0]^board[0][j]^board[i][j])!=0) return false;
    int row=0,col=0; for(int j=0;j<n;j++) row+=board[0][j]; for(int i=0;i<n;i++) col+=board[i][0];
    return row*2==n && col*2==n;
}
